package com.beerdesigner.catalog;
import jakarta.persistence.*; import java.math.BigDecimal;
@Entity @Table(name="brewing_salts") public class BrewingSalt{
 @Id private String id; private String name; private String formula; private String category; private String description;
 @Column(name="calcium_percent") private BigDecimal calciumPercent; @Column(name="magnesium_percent") private BigDecimal magnesiumPercent; @Column(name="sodium_percent") private BigDecimal sodiumPercent; @Column(name="sulfate_percent") private BigDecimal sulfatePercent; @Column(name="chloride_percent") private BigDecimal chloridePercent; @Column(name="bicarbonate_percent") private BigDecimal bicarbonatePercent;
 public String getId(){return id;} public String getName(){return name;} public String getFormula(){return formula;} public String getCategory(){return category;} public String getDescription(){return description;} public BigDecimal getCalciumPercent(){return calciumPercent;} public BigDecimal getMagnesiumPercent(){return magnesiumPercent;} public BigDecimal getSodiumPercent(){return sodiumPercent;} public BigDecimal getSulfatePercent(){return sulfatePercent;} public BigDecimal getChloridePercent(){return chloridePercent;} public BigDecimal getBicarbonatePercent(){return bicarbonatePercent;}
 public void setId(String value){id=value;} public void setName(String value){name=value;} public void setFormula(String value){formula=value;} public void setCategory(String value){category=value;} public void setDescription(String value){description=value;} public void setCalciumPercent(BigDecimal value){calciumPercent=value;} public void setMagnesiumPercent(BigDecimal value){magnesiumPercent=value;} public void setSodiumPercent(BigDecimal value){sodiumPercent=value;} public void setSulfatePercent(BigDecimal value){sulfatePercent=value;} public void setChloridePercent(BigDecimal value){chloridePercent=value;} public void setBicarbonatePercent(BigDecimal value){bicarbonatePercent=value;}
}
